import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

export const Schema = z.object({
  世界概况: z.object({
    观测史观: z.enum(['无', '唯物史观', '辉格史观', '英雄史观', '投机史观', '机械史观', '娱乐史观']).prefault('无'),
    时间: z.object({
      年份: z.coerce.number().prefault(-221).describe('负数代表公元前，不存在0年'),
      月份: z.coerce.number().transform(v => _.clamp(v, 1, 12)).prefault(6),
      日期: z.coerce.number().transform(v => _.clamp(v, 1, 31)).prefault(21),
    }).prefault({}),
    年号: z.object({
      名称: z.string().prefault('无'),
      年份: z.coerce.number().prefault(1)
    }).prefault({}),
    谶纬: z.string().prefault('暂无谶语流传。'),
    时势: z.object({
      标题: z.string().prefault('天下未定'),
      具体描述: z.string().prefault('各方势力暗流涌动，等待时机。'),
    }).prefault({}),
  }).prefault({}),

  角色档案: z.object({
    身份信息: z.object({
      姓名: z.string().prefault('未知'),
      表字: z.string().prefault('无'),
      年龄: z.coerce.number().prefault(20),
    }).prefault({}),

    社会状态: z.object({
      所在地点: z.string().prefault('未知地点'),
      所处阶层: z.string().prefault('平民'),
      职位: z.string().prefault('白身'),
      当前事件: z.string().prefault('平安无事，未卷入任何事件。'),
    }).prefault({}),

    经济状况: z.object({
      资产列表: z.record(
        z.string().describe('资产名'),
        z.object({
          收入: z.string().prefault('0'),
          支出: z.string().prefault('0'),
          说明: z.string().prefault('暂无说明'),
        }).prefault({})
      ).prefault({}),
      储备列表: z.record(
        z.string().describe('储备类型'),
        z.string().prefault('0')
      ).prefault({}),
    }).prefault({}),

    名望: z.object({
      称号: z.enum([
        '酷名贻臭', '天下衔恨', '路有恶讽', '郡县侧目', '乡议所鄙', '闾里轻嗤',
        '乡里凡庸', '察举在列', '郡国闻达', '朝野称誉', '海内仰之', '万世仪表'
      ]).prefault('乡里凡庸'),
      具体描述: z.string().prefault('尚未在世人中留下深刻印象。'),
    }).prefault({}),

    属性: z.object({
      数值: z.object({
        政治: z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0),
        统领: z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0),
        学识: z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0),
        健康: z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(50),
        风采: z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0),
        武艺: z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0),
      }).prefault({}),
      称号: z.string().prefault('无'),
    }).prefault({}),

    阶级评价: z.record(
      z.string().describe('阶级名称'),
      z.object({
        态度: z.string().prefault('中立'),
        具体描述: z.string().prefault('对你并无特殊看法。'),
      }).prefault({})
    ).prefault({}),

    过往履历: z.record(
      z.string().describe('时间与事件标题'),
      z.string().describe('具体经历或政绩描述')
    ).prefault({}),
  }).prefault({}),

  军事政治: z.object({
    势力列表: z.record(
      z.string().describe('势力名称'),
      z.object({
        类型: z.enum(['自立势力', '执掌势力', '依附势力']).prefault('自立势力'),
        势力领袖: z.string().prefault('未知'),
        势力动态: z.string().prefault('平静无波'),
        朝廷评价: z.object({
          态度: z.string().prefault('中立'),
          具体描述: z.string().prefault('朝廷对该势力暂时采取观望态度。'),
        }).prefault({}),
        其他势力评价: z.record(
          z.string().describe('其他势力名称'),
          z.object({
            态度: z.string().prefault('中立'),
            具体描述: z.string().prefault('无特殊看法。'),
          }).prefault({})
        ).prefault({}),
      }).prefault({})
    ).prefault({}),

    部队列表: z.record(
      z.string().describe('部队名称'),
      z.object({
        统领: z.string().prefault('暂无'),
        数量: z.coerce.number().prefault(0),
        士气: z.enum(['昂扬', '振奋', '平稳', '疲软', '低落']).prefault('平稳'),
        训练: z.enum(['疏于操练', '初成行列', '进退有度', '号令严明', '习战精熟']).prefault('疏于操练'),
        装备: z.enum(['锐利', '精良', '齐整', '粗备', '简陋']).prefault('粗备'),
        后勤状况: z.enum(['补给充足', '补给示警', '缺粮']).prefault('补给充足'),
        忠心状况: z.enum(['叛乱', '摇摆', '恪职', '忠诚']).prefault('摇摆'),
        动向: z.string().prefault('原地驻扎'),
        驻地: z.string().prefault('未知驻地'),
        说明: z.string().prefault('一支普通的部队。'),
      }).prefault({})
    ).prefault({}),
  }).prefault({}),

  人际网络: z.object({
    下属列表: z.record(
      z.string().describe('姓名'),
      z.object({
        官职: z.string().prefault('白身'),
        好感: z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0),
        评价: z.string().prefault('中规中矩的下属。'),
      }).prefault({})
    ).prefault({}),

    人际交往: z.record(
      z.string().describe('姓名'),
      z.object({
        官职: z.string().prefault('无'),
        好感: z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0),
        评价: z.string().prefault('泛泛之交。'),
      }).prefault({})
    ).prefault({}),

    家族信息: z.object({
      家族名: z.string().prefault('未知家族'),
      家族领袖: z.string().prefault('无'),
      家族等级: z.string().prefault('寒门'),
      家族动向: z.string().prefault('蛰伏以待天时'),
      家族子弟: z.record(
        z.string().describe('姓名'),
        z.object({
          年龄: z.coerce.number().prefault(16),
          表字: z.string().prefault('无'),
          官职: z.string().prefault('白身'),
          好感: z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0),
          评价: z.string().prefault('尚在成长中的族中子弟。'),
        }).prefault({})
      ).prefault({}),
    }).prefault({}),

    后宫信息: z.object({
      后宫动态: z.string().prefault('风平浪静'),
      嫔妃列表: z.record(
        z.string().describe('姓名'),
        z.object({
          位份: z.string().prefault('无品秩'),
          年龄: z.coerce.number().prefault(16),
          好感: z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0),
          性爱次数: z.coerce.number().prefault(0),
          评价: z.string().prefault('安静温婉。'),
          说明: z.string().prefault('刚入宫的新人。'),
        }).prefault({})
      ).prefault({}),
    }).prefault({}),

    子嗣信息: z.object({
      子嗣动态: z.string().prefault('健康成长'),
      子嗣列表: z.record(
        z.string().describe('姓名'),
        z.object({
          年龄: z.coerce.number().prefault(0),
          职位: z.string().prefault('未出阁/未入仕'),
          好感: z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(50),
          评价: z.string().prefault('惹人怜爱的幼子。'),
          说明: z.string().prefault('你的血脉。'),
        }).prefault({})
      ).prefault({}),
    }).prefault({}),
  }).prefault({}),
});

$(() => {
  registerMvuSchema(Schema);
})

