</head>
<body>
    <div class="review-container" id="content">
        <div class="loading">正在分析历史进程...</div>
    </div>

    <script>
        /* ========== 获取消息内容 ========== */
        function getMessageData() {
            var chatMessages = getChatMessages(getCurrentMessageId());
            if (!chatMessages || chatMessages.length === 0) {
                return null;
            }
            return chatMessages[0].message;
        }

        /* ========== 解析数据 ========== */
        function parseData(messageText) {
            var result = {
                review: '',
                options: []
            };

            /* 提取主标签内容 */
            var mainMatch = messageText.match(/<materialist_review>([\s\S]*?)<\/materialist_review>/);
            if (!mainMatch || !mainMatch[1]) {
                return result;
            }
            var content = mainMatch[1];

            /* 提取点评（总评） */
            var reviewMatch = content.match(/\[(点评|总评)\|([^\]]+)\]/);
            if (reviewMatch && reviewMatch[2]) {
                result.review = reviewMatch[2].trim();
            }

            /* 提取选项部分 */
            var optionsMatch = content.match(/<options>([\s\S]*?)<\/options>/);
            if (optionsMatch && optionsMatch[1]) {
                var optionsText = optionsMatch[1];
                /* 匹配所有选项 [选项|编号|内容|点评] */
                var optRegex = /\[选项\|([^\|]+)\|([^\|]+)\|([^\]]+)\]/g;
                var opt;
                while ((opt = optRegex.exec(optionsText)) !== null) {
                    result.options.push({
                        id: opt[1].trim(),
                        text: opt[2].trim(),
                        dianping: opt[3].trim()
                    });
                }
            }

            return result;
        }

        /* ========== 交互函数 ========== */
        function handleOptionClick(optionText) {
            if (typeof triggerSlash === 'function') {
                /* 点击选项后自动发送选择内容并触发AI */
                triggerSlash('/send ' + optionText + '|/trigger');
            }
        }

        /* ========== 渲染界面 ========== */
        function renderPage(data) {
            if (!data.review && (!data.options || data.options.length === 0)) {
                document.getElementById('content').innerHTML = '<div class="loading">❌ 未能提取到有效的分析数据</div>';
                return;
            }

            var html = '<div class="review-header">唯物史观分析报告</div>';

            if (data.review) {
                html += '<div class="review-content">' + data.review + '</div>';
            }

            if (data.options && data.options.length > 0) {
                html += '<div class="options-section">';
                html += '<div class="options-title">历史的岔路口（请选择你的实践方向）：</div>';

                data.options.forEach(function(opt) {
                    /* 使用转义避免引号导致HTML闭合问题 */
                    var safeText = opt.text.replace(/'/g, "\\'").replace(/"/g, '&quot;');

                    html += '<div class="option-item" onclick="handleOptionClick(\'' + safeText + '\')">';
                    html += '  <div class="option-main">';
                    html += '    <div class="option-num">' + (opt.id || '?') + '</div>';
                    html += '    <div class="option-text">' + (opt.text || '') + '</div>';
                    html += '  </div>';

                    if (opt.dianping) {
                        html += '  <div class="option-dianping">' + opt.dianping + '</div>';
                    }
                    html += '</div>';
                });

                html += '</div>';
            }

            document.getElementById('content').innerHTML = html;
        }

        /* ========== 主函数 ========== */
        function init() {
            try {
                var messageText = getMessageData();
                if (!messageText) {
                    document.getElementById('content').innerHTML =
                        '<div class="loading">❌ 无法获取历史档案</div>';
                    return;
                }
                var data = parseData(messageText);
                renderPage(data);
            } catch (error) {
                document.getElementById('content').innerHTML =
                    '<div class="loading">❌ 解析过程发生矛盾：' + error.message + '</div>';
            }
        }

        $(function() { init(); });
    </script>
</body>
</html>
