<!DOCTYPE html>
<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <!-- 强制声明为浅色主题，尽量避免系统强行反色 -->
    <meta name="color-scheme" content="light">
    <title>辉格史观点评</title>
    <style>
        :root {
            color-scheme: light;
        }

        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: "Georgia", "Times New Roman", "Microsoft YaHei", serif;
            background: transparent;
            padding: 10px;
        }

        /* 整体容器：大理石/羊皮纸质感 */
        .review-container {
            max-width: 650px;
            margin: 0 auto;
            background: #fdfbf7 !important;
            border: 1px solid #d4af37 !important;
            border-radius: 4px;
            overflow: hidden;
            box-shadow: 0 8px 25px rgba(0, 0, 0, 0.15), inset 0 0 20px rgba(212, 175, 55, 0.05) !important;
            color: #2c3e50 !important;
            position: relative;
        }

        /* 顶部装饰线 */
        .review-container::before {
            content: '';
            position: absolute;
            top: 0;
            left: 0;
            right: 0;
            height: 4px;
            background: linear-gradient(90deg, #c5a059, #f9f0a2, #c5a059) !important;
        }

        /* 标题栏 */
        .review-header {
            background: #ffffff !important;
            padding: 16px 20px;
            font-size: 18px;
            font-weight: bold;
            color: #2c3e50 !important;
            border-bottom: 1px solid #e8e0c5 !important;
            display: flex;
            align-items: center;
            letter-spacing: 1px;
        }

        /* 古典议会/法院图标 */
        .review-header::before {
            content: "🏛️";
            margin-right: 10px;
            font-size: 22px;
            filter: drop-shadow(0 2px 2px rgba(212, 175, 55, 0.3));
        }

        /* 点评正文 */
        .review-content {
            padding: 24px;
            font-size: 15px;
            line-height: 1.7;
            text-align: justify;
            background: #fdfbf7 !important;
            color: #34495e !important;
        }

        .review-content::first-letter {
            font-size: 200%;
            color: #b8860b !important;
            font-weight: bold;
            float: left;
            margin-right: 6px;
            line-height: 1;
        }

        /* 选项区域 */
        .options-section {
            padding: 20px 24px 28px 24px;
            background-color: #faf7f0 !important;
            border-top: 1px dashed #d4af37 !important;
        }

        .options-title {
            font-size: 14px;
            color: #7f8c8d !important;
            margin-bottom: 18px;
            font-weight: bold;
            display: flex;
            align-items: center;
            font-family: "Microsoft YaHei", sans-serif;
            text-transform: uppercase;
        }

        .options-title::before {
            content: "✦";
            color: #d4af37 !important;
            margin-right: 8px;
            font-size: 16px;
        }

        /* 单个选项卡片 */
        .option-item {
            margin-bottom: 16px;
            border: 1px solid #e8e0c5 !important;
            border-radius: 4px;
            background: #ffffff !important;
            cursor: pointer;
            transition: all 0.3s ease;
            position: relative;
            overflow: hidden;
            box-shadow: 0 2px 5px rgba(0,0,0,0.02) !important;
        }

        .option-item:hover {
            border-color: #d4af37 !important;
            box-shadow: 0 6px 15px rgba(212, 175, 55, 0.2) !important;
            transform: translateY(-2px);
        }

        .option-item:hover .option-num {
            background: #d4af37 !important;
            color: #ffffff !important;
            border-color: #d4af37 !important;
        }

        .option-main {
            padding: 14px 18px;
            display: flex;
            align-items: flex-start;
        }

        /* 选项编号 */
        .option-num {
            background: #f9f6ef !important;
            border: 1px solid #d4af37 !important;
            color: #b8860b !important;
            width: 26px;
            height: 26px;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 13px;
            font-weight: bold;
            margin-right: 14px;
            flex-shrink: 0;
            margin-top: 2px;
            transition: all 0.3s ease;
            font-family: "Times New Roman", serif;
        }

        /* 选项文本 */
        .option-text {
            font-size: 15px;
            color: #2c3e50 !important;
            line-height: 1.5;
            font-family: "Microsoft YaHei", sans-serif;
        }

        /* 点评批注容器：改用弹性布局避免重叠 */
        .option-dianping {
            padding: 10px 18px 12px 18px;
            background: #fdfbf7 !important;
            font-size: 13px;
            color: #7f8c8d !important;
            border-top: 1px solid #f0ead6 !important;
            font-style: italic;
            display: flex;
            align-items: flex-start;
        }

        /* 前缀标签 */
        .dianping-label {
