                return mockData;
            }
        }

        /* ========== 解析数据 ========== */
        function parseData(messageText) {
            var result = { review: '', options: [] };

            var mainMatch = messageText.match(/<speculative_review>([\s\S]*?)<\/speculative_review>/);
            if (!mainMatch || !mainMatch[1]) return result;
            var content = mainMatch[1];

            var reviewMatch = content.match(/\[(点评|总评|盘口|大盘)\|([^\]]+)\]/);
            if (reviewMatch && reviewMatch[2]) {
                result.review = reviewMatch[2].trim();
            }

            var optionsMatch = content.match(/<options>([\s\S]*?)<\/options>/);
            if (optionsMatch && optionsMatch[1]) {
                /* 优化：使用非贪婪匹配并考虑点评内可能包含特殊符号，避免提取重复或粘连 */
                var optRegex = /\[选项\|([^\|]+)\|([^\|]+)\|(.*?)\]/g;
                var opt;
                var parsedIds = {}; /* 用对象记录已解析的编号，防止循环重复渲染 */

                while ((opt = optRegex.exec(optionsMatch[1])) !== null) {
                    var currentId = opt[1].trim();
                    if (!parsedIds[currentId]) {
                        result.options.push({
                            id: currentId,
                            text: opt[2].trim(),
                            dianping: opt[3].trim()
                        });
                        parsedIds[currentId] = true;
                    }
                }
            }
            return result;
        }

        function handleOptionClick(optionText) {
            if (typeof triggerSlash === 'function') {
                triggerSlash('/send ' + optionText + '|/trigger');
            } else {
                alert("【交易确认】\\n\\n你已押注合约：\\n" + optionText + "\\n\\n(建仓指令已发送。此为预览环境，酒馆内点击将自动回复。)");
            }
        }

        function colorizeText(text) {
            var bullRegex = /(做多|稳赚|收益|抄底|套利|赢利|垄断)/g;
            var bearRegex = /(做空|风险|亏损|破产|爆仓|抛售|套现)/g;

            var colored = text;
            /* 弃用 $1 替换符，改用回调函数，防止与部分解析引擎的宏语法冲突 */
            colored = colored.replace(bullRegex, function(match) {
                return '<span class="text-bull">' + match + '</span>';
            });
            colored = colored.replace(bearRegex, function(match) {
                return '<span class="text-bear">' + match + '</span>';
            });
            return colored;
        }

        /* ========== 渲染界面 ========== */
        function renderPage(data) {
            if (!data.review && (!data.options || data.options.length === 0)) {
                document.getElementById('content').innerHTML = '<div class="loading">❌ EXCHANGE OFFLINE: 无法获取盘口数据</div>';
                return;
            }

            var html = '<div class="review-header">历史博弈·交易所盘口</div>';

            if (data.review) {
                var coloredReview = colorizeText(data.review);
                html += '<div class="review-content">' + coloredReview + '</div>';
            }

            if (data.options && data.options.length > 0) {
                html += '<div class="options-section">';
                html += '<div class="options-title">SELECT YOUR POSITION (请选择建仓方向)：</div>';

                data.options.forEach(function(opt) {
                    var safeText = opt.text.replace(/'/g, "\\'").replace(/"/g, '&quot;');
                    var cleanDianping = opt.dianping.replace(/^(点评|收益预估|风险分析|盈亏预估)[：:]\s*/, '');
                    var coloredDianping = colorizeText(cleanDianping);

                    html += '<div class="option-item" onclick="handleOptionClick(\'' + safeText + '\')">';
                    html += '  <div class="option-main">';
                    html += '    <div class="option-num">' + (opt.id || '?') + '</div>';
                    html += '    <div class="option-text">' + (opt.text || '') + '</div>';
                    html += '  </div>';

                    if (cleanDianping) {
                        html += '  <div class="option-dianping">';
                        html += '    <div class="dianping-label">盈亏评估:</div>';
                        html += '    <div class="dianping-text">' + coloredDianping + '</div>';
                        html += '  </div>';
                    }
                    html += '</div>';
                });
                html += '</div>';
            }
            document.getElementById('content').innerHTML = html;
        }

        /* ========== 主函数 ========== */
        function init() {
            var messageText = getMessageData();
            var data = parseData(messageText);
            renderPage(data);
        }

        if (typeof $ !== 'undefined') {
            $(function() { init(); });
        } else {
            window.onload = init;
        }
    </script>
</body>
</html>
