  .step-dot.done { background: var(--main-dark); }

  .summary-group { margin-bottom: var(--space-md); width: 100%; }
  .summary-label { color: var(--text-muted); font-size: var(--fs-base); letter-spacing: 0.1em; margin-bottom: var(--space-sm); display: block; text-align: center; }
  .details-container { display: none; width: 100%; flex-direction: column; gap: var(--space-lg); }

  .modal-overlay {
    position: fixed; top: 0; left: 0; width: 100%; height: 100%;
    background: rgba(0, 0, 0, 0.85); backdrop-filter: blur(4px);
    display: none; justify-content: center; align-items: center;
    z-index: 100; opacity: 0; transition: opacity 0.3s;
  }
  .modal-overlay.show { display: flex; opacity: 1; }
  .modal-content {
    background: var(--bg-card); border: 1px solid var(--main-color); border-radius: 8px;
    width: 90%; max-width: 600px; max-height: 85vh;
    display: flex; flex-direction: column; padding: var(--space-lg);
    box-shadow: 0 10px 40px rgba(0,0,0,0.6), var(--shadow-main);
  }
  .modal-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: var(--space-md); }
  .modal-title { color: var(--main-color); font-size: var(--fs-xl); letter-spacing: 0.1em; }
  .modal-close { background: none; border: none; color: var(--text-muted); font-size: 24px; cursor: pointer; transition: color 0.3s; }
  .modal-close:hover { color: var(--main-color); }
  .modal-body { flex: 1; overflow-y: auto; margin-bottom: var(--space-md); }
  .modal-textarea {
    width: 100%; min-height: 300px; background: var(--bg-input); border: 1px solid var(--border);
    color: var(--text-secondary); font-size: var(--fs-sm); padding: var(--space-sm);
    border-radius: 4px; resize: vertical; font-family: inherit; line-height: 1.6;
  }
  .modal-textarea:focus { outline: none; border-color: var(--main-dark); }

  .btn-edit {
    position: absolute; top: -10px; right: -10px; background: var(--bg-card); border: 1px solid var(--main-color);
    border-radius: 50%; width: 40px; height: 40px; font-size: 18px; display: flex; justify-content: center; align-items: center;
    cursor: pointer; color: var(--main-color); box-shadow: 0 4px 10px rgba(0,0,0,0.5); z-index: 5; transition: all 0.3s;
  }
  .btn-edit:hover { background: var(--main-color); color: #fff; transform: rotate(15deg); }

    .edit-form-group { display: flex; flex-direction: column; gap: 6px; margin-bottom: 12px; }
  .edit-form-label { font-size: var(--fs-sm); color: var(--main-color); letter-spacing: 0.1em; }
  .edit-form-input { background: var(--bg-input); border: 1px solid var(--border); color: var(--text-primary); padding: 8px; border-radius: 4px; font-family: inherit; font-size: var(--fs-sm); outline: none; width: 100%; transition: all 0.3s; }
  .edit-form-input:focus { border-color: var(--main-color); box-shadow: var(--shadow-main); }
</style>
</head>
<body>

<div class="container" id="app">
  <div class="page active" id="page-0">
    <div class="page-inner">
      <h1 class="page-title" style="font-size:var(--fs-3xl);">秦汉风云</h1>
      <p class="page-guide">六合一统，楚汉相争，大汉盛衰。<br>四百载基业，英雄辈出，你的命运，将在这金戈铁马的洪流中铭刻。</p>
      <div class="btn-row" style="margin-top:var(--space-lg);"><button class="btn" onclick="goToPage(1)">展卷入局</button></div>
    </div>
  </div>

  <div class="page" id="page-1">
    <div class="page-inner">
      <h2 class="page-title">铭刻真名</h2>
      <p class="page-guide">在浩瀚史书中留下你的印记。</p>
      <div class="input-group">
        <input class="input-field" id="input-name" type="text" placeholder="输入姓名 (必填)" maxlength="10">
        <input class="input-field" id="input-zi" type="text" placeholder="输入表字 (可不填)" maxlength="10">
        <input class="input-field" id="input-age" type="number" placeholder="输入年龄">
      </div>
      <div class="btn-row">
        <button class="btn btn-back" onclick="goToPage(0)">返回</button>
        <button class="btn" onclick="saveName()">下一步</button>
      </div>
    </div>
  </div>

  <div class="page" id="page-2">
    <div class="page-inner">
      <h2 class="page-title">天命道路</h2>
      <p class="page-guide">选择你涉足乱世的方式：是征战朝堂的权谋演义，还是隐秘幽深的宫闱秘史？</p>
      <div class="card-grid">
        <div class="card" id="mode-normal" onclick="selectMode('normal')">
          <div class="card-title">正史演绎 (自创人物)</div>
          <div class="card-desc">常规流程，建功立业，名垂青史。</div>
        </div>
        <div class="card sp-theme" id="mode-secret" onclick="selectMode('secret')">
          <div class="card-title">宫闱风月 (特殊剧本)</div>
          <div class="card-desc">掌控与沦陷，不为人知的隐秘调教。</div>
        </div>
      </div>
      <div class="btn-row">
        <button class="btn btn-back" onclick="goToPage(1)">返回</button>
        <button class="btn" onclick="saveMode()">下一步</button>
      </div>
    </div>
  </div>

  <!-- 正史演义分支 (page-3 到 page-12) -->
  <div class="page" id="page-3">
    <div class="page-inner">
      <h2 class="page-title">天下大势</h2>
      <p class="page-guide">选择你登临的时代节点，这将决定你的初始舞台。</p>
      <div id="situation-cards" class="card-list"></div>
      <div class="btn-row">
        <button class="btn btn-back" onclick="goToPage(2)">返回</button>
        <button class="btn" onclick="saveSituation()">下一步</button>
      </div>
    </div>
  </div>

  <div class="page" id="page-4">
    <div class="page-inner">
      <h2 class="page-title">观测史观</h2>
      <p class="page-guide">决定事件反映的视角？(不选则默认未定，仅影响事件口吻与评判)</p>
      <div id="history-view-cards" class="card-grid"></div>
      <div class="btn-row">
        <button class="btn btn-back" onclick="goToPage(3)">返回</button>
        <button class="btn" onclick="saveHistoryView()">下一步</button>
      </div>
    </div>
  </div>

  <div class="page" id="page-5">
    <div class="page-inner">
      <h2 class="page-title">所属阵营</h2>
      <p class="page-guide">乱世或治世，你身披何方旗帜？</p>
      <div id="faction-cards" class="card-grid"></div>
      <div class="btn-row">
        <button class="btn btn-back" onclick="goToPage(4)">返回</button>
        <button class="btn" onclick="saveFaction()">下一步</button>
      </div>
    </div>
  </div>

  <div class="page" id="page-6">
    <div class="page-inner">
      <h2 class="page-title">出身家世</h2>
      <p class="page-guide">王侯将相宁有种乎？你的出身，是荫庇也是枷锁。</p>
      <div id="class-cards" class="card-grid"></div>
      <div id="custom-position-container" class="input-group" style="display:none; margin-top: var(--space-lg); width:100%; max-width: 400px;">
          <label class="summary-label" style="margin-bottom: 8px;">自定义官职或身份 (选填)</label>
          <input class="input-field" id="input-custom-position" type="text" placeholder="留空则使用默认身份">
      </div>
      <div class="btn-row">
        <button class="btn btn-back" onclick="goToPage(5)">返回</button>
        <button class="btn" onclick="saveClass()">下一步</button>
      </div>
    </div>
  </div>

  <div class="page" id="page-7">
    <div class="page-inner">
      <h2 class="page-title">初始名望</h2>
      <p class="page-guide">你的名声在当世流传多远？(高名望需要较高的社会阶层)</p>
      <div id="reputation-cards" class="card-grid"></div>
      <div class="btn-row">
        <button class="btn btn-back" onclick="goToPage(6)">返回</button>
        <button class="btn" onclick="saveReputation()">下一步</button>
      </div>
    </div>
  </div>

  <div class="page" id="page-8">
    <div class="page-inner">
      <h2 class="page-title">所在地域</h2>
      <p class="page-guide">你的征途，将从哪片土地开始？</p>
      <div id="region-cards" class="card-grid"></div>
      <div class="input-group" style="margin-top: var(--space-lg); width:100%; max-width: 400px;">
          <label class="summary-label" style="margin-bottom: 8px;">自定义地域 (选填)</label>
          <input class="input-field" id="input-custom-region" type="text" placeholder="若上方无合意，可在此填写">
      </div>
      <div class="btn-row">
        <button class="btn btn-back" onclick="goToPage(7)">返回</button>
        <button class="btn" onclick="saveRegion()">下一步</button>
      </div>
    </div>
  </div>

  <div class="page" id="page-9">
      <div class="page-inner">
        <h2 class="page-title">天资秉赋</h2>
        <p class="page-guide">点击抽取词条，也可直接在输入框中任意修改。</p>
        <div id="talent-selection-area" style="width:100%"></div>
        <div class="btn-row">
          <button class="btn btn-back" onclick="goToPage(8)">返回</button>
          <button class="btn" onclick="saveTalent()">下一步</button>
        </div>
      </div>
  </div>

  <div class="page" id="page-10">
    <div class="page-inner">
      <h2 class="page-title">子嗣情况</h2>
      <p class="page-guide">宗族血脉，传承不息。</p>
      <div id="children-choice-cards" class="card-grid"></div>
      <div id="children-details" class="details-container">
          <div class="input-group" style="margin: 0 auto;">
            <textarea class="textarea-field" id="children-info" placeholder="请填写子嗣信息，如：长子XX十岁，聪慧过人..."></textarea>
          </div>
      </div>
      <div class="btn-row">
        <button class="btn btn-back" onclick="goToPage(9)">返回</button>
        <button class="btn" onclick="saveChildren()">下一步</button>
      </div>
    </div>
  </div>

  <div class="page" id="page-11">
    <div class="page-inner">
        <h2 class="page-title">执掌势力</h2>
        <p class="page-guide">孤身一人，归附权贵，抑或拥兵自立？</p>
        <div id="force-choice-cards" class="card-grid"></div>
        <div id="force-details-depend" class="details-container">
            <h3 class="sub-section-title" style="color:var(--main-light); text-align:center;">选择归附势力</h3>
            <div id="depend-force-cards" class="card-grid"></div>
            <div class="input-group" style="margin: 0 auto; margin-top: 12px;">
                <input class="input-field" id="force-depend-name" placeholder="或在此自定义势力名称"/>
            </div>
        </div>
        <div id="force-details-create" class="details-container">
            <h3 class="sub-section-title" style="color:var(--main-light); text-align:center;">创建你的班底</h3>
            <div class="input-group" style="margin: 0 auto;">
                <input class="input-field" id="force-name" placeholder="势力名称 (如：坞堡商队)"/>
                <input class="input-field" id="force-power" placeholder="兵力规模 (如：门客五百)"/>
                <textarea class="textarea-field" id="force-subordinates" placeholder="核心部下 (如：护卫李四)"></textarea>
            </div>
        </div>
        <div class="btn-row">
            <button class="btn btn-back" onclick="goToPage(10)">返回</button>
            <button class="btn" onclick="saveForce()">下一步</button>
        </div>
    </div>
  </div>

  <div class="page" id="page-12">
    <div class="page-inner">
      <h2 class="page-title">当前事件</h2>
      <p class="page-guide">命运已为你铺好具体的困局。</p>
      <div id="event-cards" class="card-list"></div>
      <div id="event-custom-details" class="input-group" style="display:none; margin-top: var(--space-md); width:100%; max-width: 400px;">
          <textarea class="textarea-field" id="event-custom-info" placeholder="详细描述你面临的具体危机..."></textarea>
      </div>
      <div class="btn-row">
        <button class="btn btn-back" onclick="goToPage(11)">返回</button>
        <button class="btn" onclick="saveEvent()">完成创建</button>
      </div>
    </div>
  </div>

  <!-- 宫闱风月分支 (page-13 到 page-16) -->
  <div class="page" id="page-13">
    <div class="page-inner">
      <h2 class="page-title" style="color:var(--main-sp);">风月剧本</h2>
      <p class="page-guide">权色交织，幽深不见底。选择你主导的隐秘舞台。</p>
      <div id="sp-script-cards" class="card-list"></div>
      <div class="btn-row">
        <button class="btn btn-back" onclick="goToPage(2)">返回</button>
        <button class="btn" style="border-color:var(--main-sp); color:var(--main-sp);" onclick="saveSpScript()">下一步</button>
      </div>
    </div>
  </div>

  <div class="page" id="page-14">
    <div class="page-inner">
      <h2 class="page-title" style="color:var(--main-sp);">你的身份</h2>
      <p class="page-guide">披上伪装，在这个剧本中，你是谁？</p>
      <div id="sp-identity-cards" class="card-grid"></div>
      <div class="btn-row">
        <button class="btn btn-back" onclick="goToPage(13)">返回</button>
        <button class="btn" style="border-color:var(--main-sp); color:var(--main-sp);" onclick="saveSpIdentity()">下一步</button>
      </div>
    </div>
  </div>

  <div class="page" id="page-15">
    <div class="page-inner">
      <h2 class="page-title" style="color:var(--main-sp);">折辱对象</h2>
      <p class="page-guide">昔日高高在上的贵主，如今沦为你掌中的玩物。</p>
      <div id="sp-target-cards" class="card-grid"></div>
      <div class="btn-row">
        <button class="btn btn-back" onclick="goToPage(14)">返回</button>
        <button class="btn" style="border-color:var(--main-sp); color:var(--main-sp);" onclick="saveSpTarget()">下一步</button>
      </div>
    </div>
  </div>

  <div class="page" id="page-16">
    <div class="page-inner">
      <h2 class="page-title" style="color:var(--main-sp);">调教方式</h2>
      <p class="page-guide">不染血腥的调教，最为刻骨铭心。</p>
      <div id="sp-method-cards" class="card-list"></div>
      <div class="btn-row">
        <button class="btn btn-back" onclick="goToPage(15)">返回</button>
        <button class="btn" style="border-color:var(--main-sp); color:var(--main-sp);" onclick="saveSpMethod()">完成创建</button>
      </div>
    </div>
  </div>

    <!-- 最终总览页 (page-17) -->
  <div class="page" id="page-17">
    <div class="page-inner">
        <button class="btn-edit" onclick="openEditMenu()" title="修改已选设定">✏️</button>
        <h2 class="page-title" id="summary-title">史记简编</h2>
        <p class="page-guide">卷宗已成，你可在此补充最后的人生留白。</p>
        <div id="summary-info" class="info-box" style="text-align: left; line-height: 2.2; width:100%;"></div>

        <div id="summary-inputs" class="details-container" style="display:none; width: 100%;">
            <div class="summary-group">
                <label class="summary-label" for="input-family-info">背景概况 (可选)</label>
                <textarea id="input-family-info" class="textarea-field" placeholder="昔日门风、或隐秘过往..."></textarea>
            </div>
            <div class="summary-group">
                <label class="summary-label" for="input-relations">人脉纠葛 (可选)</label>
                <textarea id="input-relations" class="textarea-field" placeholder="宿敌旧友、恩怨牵扯..."></textarea>
            </div>
            <div class="summary-group">
                <label class="summary-label" for="input-custom">志向与执念 (可选)</label>
                <textarea id="input-custom" class="textarea-field" placeholder="此生欲求何事..."></textarea>
            </div>
            <div class="summary-group">
                <label class="summary-label" for="input-custom-assets">自定义资产/道具 (可选)</label>
                <textarea id="input-custom-assets" class="textarea-field" placeholder="宝剑私库、或是调教奇物..."></textarea>
            </div>
        </div>

        <div class="btn-row">
            <button class="btn btn-back" onclick="goBackFromSummary()">返回修改</button>
            <button class="btn btn-back" onclick="showPreviewModal()" style="border-color: var(--main-dark); color: var(--main-light);">预览设定</button>
            <button class="btn" id="btn-confirm-final" onclick="onConfirm()">入局</button>
        </div>
    </div>
  </div>

  <!-- 铅笔修改弹窗 -->
  <div class="modal-overlay" id="edit-menu-modal">
    <div class="modal-content" style="max-width: 500px;">
      <div class="modal-header">
        <div class="modal-title" id="edit-modal-title" style="font-size: var(--fs-lg);">直接修改设定</div>
        <button class="modal-close" onclick="closeEditMenu()">×</button>
      </div>
      <div class="modal-body" id="edit-list-container">
        <!-- 动态生成修改表单 -->
      </div>
      <div class="btn-row" style="margin-top: 0;">
        <button class="btn btn-back" onclick="closeEditMenu()">取消</button>
        <button class="btn" id="btn-save-edit" onclick="saveEditedInfo()">保存修改</button>
      </div>
    </div>
  </div>

  <div class="modal-overlay" id="preview-modal">
    <div class="modal-content">
      <div class="modal-header">
        <div class="modal-title">设定总览</div>
        <button class="modal-close" onclick="closePreviewModal()">×</button>
      </div>
      <div class="modal-body">
        <textarea class="modal-textarea" id="preview-textarea" readonly></textarea>
      </div>
      <div class="btn-row" style="margin-top: 0;">
        <button class="btn btn-back" onclick="closePreviewModal()">关闭</button>
        <button class="btn" id="btn-copy" onclick="copyPreviewText()">复制信息</button>
      </div>
    </div>
  </div>

  <div class="step-indicator" id="step-indicator"></div>
</div>

<script>
const worldData = {
    situations: [
        { year: '前221年', title: '前221年 - 六合一统', reign: '始皇帝二十六年', desc: '秦王政灭齐，天下归一。自称始皇帝，废分封立郡县，书同文车同轨。' },
        { year: '前220年', title: '前220年 - 北却匈奴', reign: '始皇帝二十七年', desc: '蒙恬率三十万大军北逐匈奴，连接六国旧长城，万里长城横亘北疆。' },
        { year: '前219年', title: '前219年 - 南岭烽烟', reign: '始皇帝二十八年', desc: '尉屠雎发卒五十万分五军南下，与百越战于西江，屠雎亡，伏尸数十万。' },
        { year: '前214年', title: '前214年 - 渠成越定', reign: '始皇帝三十三年', desc: '史禄凿灵渠，引湘入漓。粮道通，秦军定岭南，置三郡。' },
        { year: '前213年', title: '前213年 - 焚书坑儒', reign: '始皇帝三十四年', desc: '李斯请焚百家之书。四百六十余儒生方士被坑于咸阳。' },
        { year: '前210年', title: '前210年 - 沙丘之变', reign: '始皇帝三十七年', desc: '秦始皇崩于沙丘。赵高李斯矫诏赐死扶苏，立胡亥。秦基动摇。' },
        { year: '前209年', title: '前209年 - 大泽揭竿', reign: '秦二世元年', desc: '陈胜吴广遇雨失期，诛县尉举兵，号"大楚兴陈胜王"。' },
        { year: '前208年', title: '前208年 - 破釜沉舟', reign: '秦二世二年', desc: '项羽渡漳河破釜沉舟，九战破秦军，杀苏角虏王离。' },
        { year: '前207年', title: '前207年 - 约法指鹿', reign: '汉元年', desc: '赵高指鹿为马。刘邦破武关入咸阳，秦王子婴降。约法三章。' },
        { year: '前206年', title: '前206年 - 鸿门惊宴', reign: '汉元年', desc: '项羽入关屯鸿门，刘邦谢罪。项羽背约封诸侯，自号西楚霸王。' },
        { year: '前205年', title: '前205年 - 彭城之溃', reign: '汉二年', desc: '刘邦统五十六万联军袭彭城，项羽三万精骑大破之。' },
        { year: '前203年', title: '前203年 - 鸿沟为界', reign: '汉四年', desc: '楚汉相持广武。约以鸿沟为界中分天下。' },
        { year: '前202年', title: '前202年 - 垓下悲歌', reign: '汉五年', desc: '刘邦围项羽于垓下，四面楚歌。项羽乌江自刎。刘邦称帝立汉。' },
        { year: '前201年', title: '前201年 - 白登之围', reign: '汉六年', desc: '刘邦击韩王信叛军，被冒顿单于围白登山七日。陈平用计方解。' },
        { year: '前196年', title: '前196年 - 异姓殒命', reign: '汉十一年', desc: '韩信被吕后诱杀，彭越醢为肉酱，英布反被诛。异姓诸侯尽除。' },
        { year: '前194年', title: '前194年 - 吕氏临朝', reign: '汉惠帝元年', desc: '刘邦崩惠帝立。吕后毒杀赵王如意，残害戚夫人。吕后称制。' },
        { year: '前188年', title: '前188年 - 诸吕封王', reign: '汉惠帝七年', desc: '惠帝崩，吕后连立少帝，大封吕氏子弟为王侯。' },
        { year: '前180年', title: '前180年 - 荡吕兴治', reign: '汉文帝元年', desc: '吕后崩，周勃陈平合谋诛诸吕，迎代王刘恒即位。' },
        { year: '前157年', title: '前157年 - 景帝继统', reign: '汉景帝前元元年', desc: '文帝崩，景帝刘启即位。晁错上削藩策，矛盾激化。' },
        { year: '前154年', title: '前154年 - 七国之乱', reign: '汉景帝前元三年', desc: '吴楚等七国以"清君侧"起兵。周亚夫三月平叛，诸侯权削。' },
        { year: '前141年', title: '前141年 - 文景之成', reign: '汉景帝后元三年', desc: '太仓之粟陈陈相因，百姓殷富。文景之治达于极盛。' },
        { year: '前140年', title: '前140年 - 独尊儒术', reign: '建元元年', desc: '武帝采董仲舒议，罢黜百家独尊儒术，立五经博士。' },
        { year: '前138年', title: '前138年 - 凿空西域', reign: '建元三年', desc: '张骞应募使西域，遭匈奴扣留十余年，凿空之功开丝路先河。' },
        { year: '前133年', title: '前133年 - 马邑之谋', reign: '元光二年', desc: '汉设伏兵马邑欲歼匈奴单于，事泄无功。汉匈和亲断绝。' },
        { year: '前129年', title: '前129年 - 龙城飞将', reign: '元光六年', desc: '四路出击匈奴，唯卫青直捣龙城得胜。' },
        { year: '前127年', title: '前127年 - 河套之复', reign: '元朔二年', desc: '卫青迂回匈奴后方夺取河套，置朔方郡，长安北线得保。' },
        { year: '前124年', title: '前124年 - 漠南之捷', reign: '元朔五年', desc: '卫青大破右贤王，俘获男女万五千人。拜大将军。' },
        { year: '前121年', title: '前121年 - 断臂河西', reign: '元狩二年', desc: '霍去病两次出征河西，浑邪王降汉，河西四郡立。' },
        { year: '前119年', title: '前119年 - 封狼居胥', reign: '元狩四年', desc: '卫青霍去病深入漠北。霍去病封狼居胥，漠南无王庭。' },
        { year: '前110年', title: '前110年 - 封禅泰山', reign: '元封元年', desc: '武帝巡边勒兵十余万，封禅泰山，改元元封。' },
        { year: '前104年', title: '前104年 - 欲求汗血', reign: '太初元年', desc: '武帝遣李广利征大宛求汗血马，兵破其城得善马。' },
        { year: '前99年', title: '前99年 - 天山之战', reign: '天汉二年', desc: '李广利苦战天山死伤惨重。李陵五千步卒被困投降。' },
        { year: '前97年', title: '前97年 - 贰师再出', reign: '天汉四年', desc: '李广利再征匈奴，与右贤王战，无功而还。' },
        { year: '前95年', title: '前95年 - 轮台罪己', reign: '太始二年', desc: '武帝下轮台诏，拒屯田之议，历陈连年征战之弊，息兵务农。' },
        { year: '前91年', title: '前91年 - 巫蛊之祸', reign: '征和二年', desc: '江充构陷太子据，长安血战五日。太子败死，卫氏尽灭。' },
        { year: '前90年', title: '前90年 - 燕然之败', reign: '征和三年', desc: '李广利深入漠北遭单于夜袭，汉军大溃。广利降匈奴。' },
        { year: '前87年', title: '前87年 - 托孤霍光', reign: '后元二年', desc: '武帝病笃，立幼子弗陵，霍光辅政，执掌朝政大权。' },
        { year: '前74年', title: '前74年 - 废立之威', reign: '元平元年', desc: '昭帝崩。霍光立昌邑王刘贺，二十七日后废之，立宣帝。' },
        { year: '前68年', title: '前68年 - 霍氏之覆', reign: '地节二年', desc: '霍光病逝。霍氏宗族谋反事泄被族灭。' },
        { year: '前66年', title: '前66年 - 孝宣中兴', reign: '地节四年', desc: '宣帝任用循吏，治吏治民。国力复振，史称孝宣中兴。' },
        { year: '前51年', title: '前51年 - 南附朝汉', reign: '甘露三年', desc: '匈奴内乱，呼韩邪单于南附朝汉，匈奴自此称臣。' },
        { year: '前48年', title: '前48年 - 宣崩元替', reign: '黄龙元年', desc: '宣帝崩，元帝即位，柔仁好儒，重用宦官石显。' },
        { year: '前33年', title: '前33年 - 昭君出塞', reign: '竟宁元年', desc: '呼韩邪单于入朝请婚，王昭君赐之出塞。汉匈边境无战事。' },
        { year: '前9年', title: '前9年 - 谦恭任之', reign: '元延四年', desc: '王莽以谦恭俭让闻名，继任大司马，权倾朝野。' },
        { year: '前7年', title: '前7年 - 成帝荒政', reign: '绥和二年', desc: '成帝宠赵氏姐妹，外戚王氏专权，朝政败坏。' },
        { year: '前1年', title: '前1年 - 哀帝短祚', reign: '元寿二年', desc: '哀帝即位欲抑王氏，宠董贤，六年而崩。王莽复出。' },
        { year: '公元6年', title: '公元6年 - 居摄践祚', reign: '居摄元年', desc: '平帝崩，王莽立孺子婴，自称假皇帝。刘崇讨莽失败。' },
        { year: '公元8年', title: '公元8年 - 新朝代汉', reign: '始建国元年', desc: '王莽即真天子位，建国号"新"，强行改制，天下大乱。' },
        { year: '公元23年', title: '公元23年 - 昆阳之战', reign: '地皇四年', desc: '刘秀三千人夜袭莽军，莽军大溃。王莽被杀。' },
        { year: '公元25年', title: '公元25年 - 鄗南称尊', reign: '建武元年', desc: '刘秀即位于鄗南是为光武帝。定都洛阳。' },
        { year: '公元27年', title: '公元27年 - 赤眉陨落', reign: '建武三年', desc: '赤眉军粮尽出关，光武遣将夹击，十余万众投降。' },
        { year: '公元36年', title: '公元36年 - 光武复统', reign: '建武十二年', desc: '吴汉破成都杀公孙述，平定巴蜀。天下复归一统。' },
        { year: '公元40年', title: '公元40年 - 征度之际', reign: '建武十六年', desc: '交趾二征反。光武行度田核查垦田，引发豪强暴乱。' },
        { year: '公元57年', title: '公元57年 - 建武之终', reign: '建武中元二年', desc: '光武帝赐印"汉委奴国王"。光武崩，明帝继位。' },
        { year: '公元73年', title: '公元73年 - 投笔从戎', reign: '永平十六年', desc: '明帝击北匈奴，班超假司马使西域，斩匈奴使收服鄯善。' },
        { year: '公元75年', title: '公元75年 - 疏勒孤守', reign: '永平十八年', desc: '明帝崩西域大乱。班超拒诏不还，独留疏勒镇抚西域。' },
        { year: '公元88年', title: '公元88年 - 章和之末', reign: '章和二年', desc: '章帝崩，十岁和帝立。窦太后临朝，窦宪居权。' },
        { year: '公元89年', title: '公元89年 - 燕然勒功', reign: '永元元年', desc: '窦宪为赎死罪出击北匈奴，大破之，登燕然刻石。' },
        { year: '公元91年', title: '公元91年 - 金微山摧', reign: '永元三年', desc: '窦宪再遣兵直抵金微山，单于遁走。北匈奴西迁。' },
        { year: '公元92年', title: '公元92年 - 永元之始', reign: '永元四年', desc: '和帝结宦官郑众，收窦宪印绶令其自杀，夺回皇权。' },
        { year: '公元106年', title: '公元106年 - 元兴之殇', reign: '元兴元年', desc: '和帝英年早逝。百日殇帝继位旋夭。邓太后临朝。' }
