    getClassesByFaction: function(yearStr, faction) {
        if (!yearStr || !faction) return [];
        let evts = this.crisisData[yearStr]?.[faction];
        let classList = [];
        if (evts) {
            Object.keys(evts).forEach(className => {
                let config = this.classConfigPool[className] || { maxRep: 4, position: '组织成员', assets: { 产业: '无定产', 金钱: '数金', 粮食: '足够口粮' } };
                classList.push({ name: className, maxRep: config.maxRep, position: config.position, assets: config.assets });
            });
        }
        if (classList.length === 0) classList.push({ name: '无名之辈', maxRep: 2, position: '流民或底层', assets: { 产业: '无', 金钱: '极少', 粮食: '匮乏' } });
        return classList;
    },
