    getSpecificEvents: function(year, className) {
        let evts = [];
        if (this.crisisData[year]) {
            for (let faction in this.crisisData[year]) {
                if (this.crisisData[year][faction][className]) {
                    this.crisisData[year][faction][className].forEach(e => {
                        evts.push({ name: e, type: 'specific' });
                    });
                }
            }
        }
