        if (customAssetsText) assetLine += `额外资产补充：${customAssetsText}。`;
        lines.push(assetLine);

        if (userData.children.has) lines.push(`【子嗣情况】：${userData.children.info}`);
        if (userData.force.type === '归附势力') lines.push(`【势力背景】：目前归附于 ${userData.force.name}。`);
        else if (userData.force.type === '自立山头') lines.push(`【势力背景】：建立山头 ${userData.force.name}，掌握规模/兵力 ${userData.force.power}，核心部下有 ${userData.force.subordinates}。`);
        else lines.push(`【势力背景】：暂无班底，孑然一身。`);

        lines.push(`【当前遭遇事件】：${userData.event}`);
    } else {
        lines.push('我的秦汉宫闱风月特殊剧本设定已生成，请严格基于以下设定，侧重细腻的心理博弈、权力碾压与非血腥的尊严剥夺进行推演：\n');
        lines.push(`【基本身份】：姓名 ${userData.name}${userData.zi ? '，字'+userData.zi : ''}${userData.age ? '，'+userData.age+'岁' : ''}。`);
        lines.push(`【剧本背景】：${userData.spScript.title} - ${userData.spScript.desc}`);
        lines.push(`【我的身份】：${userData.spIdentity.name} - ${userData.spIdentity.desc}`);
        lines.push(`【调教对象】：${userData.spTarget.name} - ${userData.spTarget.desc}`);
        lines.push(`【摧毁方式】：${userData.spMethod.name} - ${userData.spMethod.desc}`);
        lines.push(`【推演要求】：避免断肢等极端血腥情节，专注于权力掌控下的屈服、反差感与隐秘的风月纠葛。`);
    }

    let fInfo = document.getElementById('input-family-info').value.trim();
    let rInfo = document.getElementById('input-relations').value.trim();
    let cInfo = document.getElementById('input-custom').value.trim();
    if(fInfo || rInfo || cInfo) {
        lines.push('\n【补充设定】：');
        if(fInfo) lines.push(`背景概况：${fInfo}`);
        if(rInfo) lines.push(`人脉纠葛：${rInfo}`);
        if(cInfo) lines.push(`志向与执念：${cInfo}`);
    }

    lines.push('\n命运的竹简已然铺开，请以白描手法和符合时代设定的语言，直接开始描绘我当下面临的具体情境与抉择。');

    return lines.join('\n');
}

