        } else if (f.isObj) {
            val = (userData[f.key] && userData[f.key][f.objKey]) ? userData[f.key][f.objKey] : '';
        } else {
            val = userData[f.key] || '';
        }

        let inputHtml = '';
        if (f.type === 'textarea') {
