        if (id.startsWith('asset_')) {
            let key = id === 'asset_chan' ? '产业' : (id === 'asset_jin' ? '金钱' : '粮食');
            if(!userData.assets) userData.assets = {};
            userData.assets[key] = val;
        } else if (id.startsWith('force_')) {
            let key = id === 'force_name' ? 'name' : (id === 'force_power' ? 'power' : 'subordinates');
            if(!userData.force) userData.force = {};
            userData.force[key] = val;
        } else if (id.startsWith('talent_')) {
            let key = id.replace('talent_', '');
            if(!userData.talents) userData.talents = {};
            userData.talents[key] = val;
        } else if (['spScript', 'spIdentity', 'spTarget', 'spMethod'].includes(id)) {
            let objKey = id === 'spScript' ? 'title' : 'name';
            if(userData[id]) {
                userData[id][objKey] = val;
            } else {
                userData[id] = { [objKey]: val };
