      setText('#char-event', soc.当前事件 || '平安无事');

      setText('#char-fame', char.名望?.称号 || '无');
      setText('#char-fame-desc', char.名望?.具体描述 || '无');

      const attrs = char.属性?.数值 || {};
      setText('#attr-title', char.属性?.称号 || '无');
      const renderAttr = (id, val) => {
          setText(`#attr-${id}-val`, val);
          $(`#attr-${id}-bar`).css('width', `${_.clamp((val + 100) / 2, 0, 100)}%`);
      };
      renderAttr('pol', attrs.政治 || 0);
      renderAttr('ldr', attrs.统领 || 0);
      renderAttr('knw', attrs.学识 || 0);
      renderAttr('hp', attrs.健康 || 50);
      renderAttr('chm', attrs.风采 || 0);
      renderAttr('mrt', attrs.武艺 || 0);

      /* --- 3. 经济声誉 --- */
      const eco = char.经济状况 || {};
      const assetHtml = Object.entries(eco.资产列表 || {}).map(([k, v]) =>
        `<li class="list-item" style="flex-direction:column; align-items:flex-start;">
          <div><span style="font-weight:bold; color:var(--ink-dark);">${k}</span></div>
          <div style="font-size:12px; color:#5a4b3d; margin-top:2px;">入: ${v.收入} | 出: ${v.支出}</div>
          <div style="font-size:11px; color:#721c1c; margin-top:2px;">说明: ${v.说明}</div>
        </li>`
      ).join('');
      setHtml('#asset-list', assetHtml || '<li class="list-item" style="justify-content:center;">暂无资产</li>');

      const reserveHtml = Object.entries(eco.储备列表 || {}).map(([k, v]) =>
        `<div class="info-item"><span class="info-label">${k}</span><span class="info-value" style="color:var(--ink-dark);">${formatNum(v)}</span></div>`
      ).join('');
      setHtml('#reserve-grid', reserveHtml || '<div class="info-item">暂无储备</div>');

      const evalHtml = Object.entries(char.阶级评价 || {}).map(([k, v]) =>
        `<li class="list-item" style="flex-direction:column; align-items:flex-start;">
          <div>${k} <span class="badge badge-neutral">${v.态度}</span></div>
          <div style="font-size:12px; color:#5a4b3d; margin-top:2px;">${v.具体描述}</div>
        </li>`
      ).join('');
      setHtml('#eval-list', evalHtml || '<li class="list-item" style="justify-content:center;">无评价</li>');

      const histHtml = Object.entries(char.过往履历 || {}).map(([k, v]) =>
        `<li class="list-item" style="flex-direction:column; align-items:flex-start;">
          <div style="font-weight:bold; color:var(--qin-red);">${k}</div>
          <div style="font-size:12px; line-height:1.5; margin-top:4px; color:var(--ink-dark);">${v}</div>
        </li>`
      ).join('');
      setHtml('#hist-list', histHtml || '<li class="list-item" style="justify-content:center;">暂无履历</li>');

      /* --- 4. 天下势力 (独立) --- */
      const mil = _.get(sd, '军事政治', {});
      const net = _.get(sd, '人际网络', {});

      const facHtml = Object.entries(mil.势力列表 || {}).map(([k, v]) => {
        let otherEvalHtml = Object.entries(v.其他势力评价 || {}).map(([ok, ov]) =>
          `<div><span style="color:var(--ink-dark);">${ok}</span>: ${ov.态度} <span style="font-size:10px;">(${ov.具体描述})</span></div>`
        ).join('');
        if (!otherEvalHtml) otherEvalHtml = '<div>无其他评价</div>';

        return `<li class="list-item" style="flex-direction:column; align-items:flex-start;">
          <div style="width:100%; border-bottom: 1px solid var(--bronze-gold); padding-bottom:4px;">
            <span style="font-weight:bold; font-size:15px; color:var(--qin-red);">${k}</span>
            <span class="badge badge-neutral">${v.类型}</span>
          </div>
          <div class="sub-grid" style="width:100%; margin-top:6px;">
            <span>领袖: ${v.势力领袖}</span>
            <span style="grid-column: span 2;">朝廷态度: ${v.朝廷评价?.态度 || '未知'}</span>
          </div>
          <div style="font-size:12px; color:#5a4b3d; margin-top:4px; width:100%;">
            <div style="font-weight:bold;">势力动态:</div>
            <div>${v.势力动态}</div>
          </div>
          <div style="font-size:11px; color:#8b795e; margin-top:4px; width:100%; background:rgba(0,0,0,0.03); padding:4px;">
            <div style="font-weight:bold;">其他势力评价:</div>
            ${otherEvalHtml}
          </div>
        </li>`;
      }).join('');
      setHtml('#fac-list', facHtml || '<li class="list-item" style="justify-content:center;">暂无势力</li>');

      /* --- 5. 麾下兵将 (部曲与下属) --- */
      const armyHtml = Object.entries(mil.部队列表 || {}).map(([k, v]) => {
        let loyClass = v.忠心状况 === '叛乱' ? 'badge-bad' : (v.忠心状况 === '摇摆' ? 'badge-warn' : 'badge-good');
        let supClass = v.后勤状况 === '缺粮' ? 'badge-bad' : (v.后勤状况 === '补给示警' ? 'badge-warn' : 'badge-good');
        return `<li class="list-item" style="flex-direction:column; align-items:flex-start;">
          <div style="width:100%; display:flex; justify-content:space-between; font-weight:bold; color:var(--ink-dark);">
            <span>${k} <span class="badge ${loyClass}">${v.忠心状况}</span></span>
            <span style="color:var(--qin-red);">${formatNum(v.数量)} 人</span>
          </div>
          <div style="width:100%; display:grid; grid-template-columns:1fr 1fr; font-size:12px; margin-top:6px; color:#5a4b3d; gap:4px;">
            <span>统领: ${v.统领}</span><span>驻地: ${v.驻地}</span>
            <span>士气: ${v.士气}</span><span>补给: <span class="${supClass}" style="padding:1px 4px;border-radius:2px;font-size:10px;">${v.后勤状况}</span></span>
            <span>训练: ${v.训练}</span><span>装备: ${v.装备}</span>
          </div>
          <div style="font-size:12px; color:var(--qin-red); margin-top:4px; font-weight:bold;">动向: ${v.动向}</div>
          <div style="font-size:11px; color:#8b795e; margin-top:2px;">说明: ${v.说明}</div>
        </li>`;
      }).join('');
      setHtml('#army-list', armyHtml || '<li class="list-item" style="justify-content:center;">暂无部队</li>');

      const subHtml = Object.entries(net.下属列表 || {}).map(([k, v]) =>
        `<li class="list-item" style="flex-direction:column; align-items:flex-start;">
           <div style="width:100%; display:flex; justify-content:space-between;">
             <span>${k} <span style="font-size:11px; color:#5a4b3d;">(${v.官职})</span></span>
             <span style="font-size:12px; color:var(--qin-red);">好感: ${v.好感}</span>
           </div>
           <div style="font-size:11px; color:#8b795e; margin-top:2px;">评价: ${v.评价}</div>
         </li>`
      ).join('');
      setHtml('#sub-list', subHtml || '<li class="list-item" style="justify-content:center;">暂无下属</li>');

      /* --- 6. 宗族与交游 --- */
      const relHtml = Object.entries(net.人际交往 || {}).map(([k, v]) =>
        `<li class="list-item" style="flex-direction:column; align-items:flex-start;">
           <div style="width:100%; display:flex; justify-content:space-between;">
             <span>${k} <span style="font-size:11px; color:#5a4b3d;">(${v.官职})</span></span>
             <span style="font-size:12px;">好感: ${v.好感}</span>
           </div>
           <div style="font-size:11px; color:#8b795e; margin-top:2px;">评价: ${v.评价}</div>
         </li>`
      ).join('');
      setHtml('#rel-list', relHtml || '<li class="list-item" style="justify-content:center;">暂无交往</li>');

      const fam = net.家族信息 || {};
      setText('#fam-name', fam.家族名 || '未知');
      setText('#fam-leader', fam.家族领袖 || '无');
      setText('#fam-lvl', fam.家族等级 || '寒门');
      setText('#fam-dyn', fam.家族动向 || '无');

      const famMemHtml = Object.entries(fam.家族子弟 || {}).map(([k, v]) =>
        `<li class="list-item" style="flex-direction:column; align-items:flex-start;">
           <div style="width:100%; display:flex; justify-content:space-between;">
             <span>${k} <span style="font-size:11px; color:#5a4b3d;">(${v.年龄}岁 | ${v.表字!== '无'? v.表字: '无字'} | ${v.官职})</span></span>
             <span style="font-size:12px; color:var(--qin-red);">好感: ${v.好感}</span>
           </div>
           <div style="font-size:11px; color:#8b795e; margin-top:2px;">评价: ${v.评价}</div>
         </li>`
      ).join('');
      setHtml('#fam-mem-list', famMemHtml || '<li class="list-item" style="justify-content:center;">暂无子弟</li>');

      /* --- 7. 内闱与子嗣 --- */
      const harem = net.后宫信息 || {};
      setText('#harem-dyn', harem.后宫动态 || '无');
      const hmHtml = Object.entries(harem.嫔妃列表 || {}).map(([k, v]) => {
          const details = encodeURIComponent(JSON.stringify(v));
          return `<li class="list-item clickable-item hm-item" data-name="${k}" data-details="${details}">
            <div style="width:100%;display:flex;justify-content:space-between;align-items:center;">
              <span>${k} <span style="font-size:11px;color:var(--qin-red);">[${v.位份}]</span></span>
              <span style="font-size:12px;color:#5a4b3d;">年龄: ${v.年龄}岁 | 好感: <span style="color:var(--qin-red);font-weight:bold;">${v.好感}</span></span>
            </div>
          </li>`;
      }).join('');
      setHtml('#harem-list', hmHtml || '<li class="list-item" style="justify-content:center;">暂无后宫</li>');

      const childInfo = net.子嗣信息 || {};
      setText('#child-dyn', childInfo.子嗣动态 || '暂无');
      const childHtml = Object.entries(childInfo.子嗣列表 || {}).map(([k, v]) =>
        `<li class="list-item" style="flex-direction:column; align-items:flex-start;">
          <div style="width:100%; display:flex; justify-content:space-between;">
            <span>${k} <span style="font-size:11px; color:#5a4b3d;">(${v.年龄}岁)</span></span>
            <span style="font-size:12px; color:var(--qin-red);">好感: ${v.好感}</span>
          </div>
          <div style="font-size:11px; color:#8b795e; margin-top:2px;">${v.职位} | ${v.评价}</div>
          <div style="font-size:10px; color:#5a4b3d; margin-top:2px;">说明: ${v.说明}</div>
        </li>`
      ).join('');
      setHtml('#child-list', childHtml || '<li class="list-item" style="justify-content:center;">暂无子嗣</li>');

      bindEvents();
    }

    /* 弹窗立绘状态变量 */
    let currentNormalSrc = '';
    let currentNsfwSrc = '';
    let currentIsNsfw = false;
    let canToggleNsfw = false;

    function bindEvents() {
      $('.section-header').off('click').on('click', function() {
        $(this).toggleClass('collapsed').next('.section-content').toggleClass('hidden');
      });

      $('.hm-item').off('click').on('click', function() {
        const name = $(this).data('name');
        const data = JSON.parse(decodeURIComponent($(this).data('details')));

        $('#m-name').text(name);
        $('#m-title').text(data.位份 || '无');
        $('#m-age').text(`年龄: ${data.年龄}岁`);
        $('#m-fav').text(data.好感 || 0);
        $('#m-sex').text(data.性爱次数 || 0);
        $('#m-eval').text(data.评价 || '无');
        $('#m-desc').text(data.说明 || '无说明');

        /* 立绘处理逻辑 */
        const fav = parseInt(data.好感) || 0;
        const pData = portraitsData[name];

        if (pData) {
            currentNormalSrc = pData.normal;
            currentNsfwSrc = pData.nsfw;
            currentIsNsfw = false;
            canToggleNsfw = (fav >= 61 && !!currentNsfwSrc);

            $('#m-portrait').attr('src', currentNormalSrc).show();
            $('#m-portrait-tip').show();

            if (canToggleNsfw) {
                $('#m-portrait-tip').text('✦ 点击画卷可更衣 ✦');
                $('#m-portrait').css('cursor', 'pointer');
            } else {
                $('#m-portrait-tip').text('✦ 佳人画卷 ✦ (好感61可更衣)');
                $('#m-portrait').css('cursor', 'default');
            }
        } else {
            $('#m-portrait').hide();
            $('#m-portrait-tip').hide();
        }

        $('#harem-modal').fadeIn(200).css('display', 'flex');
      });

      /* 立绘点击切换事件 */
      $('#m-portrait').off('click').on('click', function() {
          if (canToggleNsfw) {
              currentIsNsfw = !currentIsNsfw;
              /* 切换透明度动画避免生硬闪烁 */
              $(this).css('opacity', 0.5);
              setTimeout(() => {
                  $(this).attr('src', currentIsNsfw ? currentNsfwSrc : currentNormalSrc).css('opacity', 1);
              }, 150);
          }
      });

      $('.modal-close, .modal-overlay').off('click').on('click', function(e) {
        if (e.target === this) $('#harem-modal').fadeOut(200);
      });
    }

    async function init() {
      await waitGlobalInitialized('Mvu');
      populateCharacterData();
      eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, populateCharacterData);
    }

    $(errorCatched(init));
  </script>
</head>
<body>
  <div class="memorial-container">
    <div class="memorial-header">
      <div class="header-title">人 物 志</div>
      <div class="header-subtitle">
        <span id="sys-era"></span> | <span id="sys-time"></span>
      </div>
      <div class="header-quote" id="sys-quote"></div>
    </div>

    <!-- 1. 身份档案 -->
    <div class="section">
      <div class="section-header collapsed"><span>◆ 身份档案</span></div>
      <div class="section-content hidden">
        <div class="info-item" style="border:none;">
          <div>
            <span id="char-name" style="font-size:22px; font-weight:bold; font-family:'Ma Shan Zheng', cursive; color:var(--qin-red);"></span>
            <span id="char-zi" style="font-size:16px; font-family:'Ma Shan Zheng', cursive; margin-left:6px; color:var(--ink-dark);"></span>
          </div>
          <span id="char-age" style="font-size:13px; color:#5a4b3d; margin-top:2px;"></span>
        </div>

        <div class="info-grid" style="margin-top:12px;">
          <div class="info-item"><span class="info-label">所在地点</span><span id="char-loc" class="info-value"></span></div>
          <div class="info-item"><span class="info-label">职位</span><span id="char-job" class="info-value"></span></div>
          <div class="info-item"><span class="info-label">名望称号</span><span id="char-fame" class="info-value" style="color:var(--qin-red);"></span></div>
          <div class="info-item"><span class="info-label">属性天资</span><span id="attr-title" class="info-value" style="color:var(--ink-dark);"></span></div>
        </div>

        <div class="narrative-box"><div class="narrative-box-title">当前事件</div><span id="char-event"></span></div>
        <div class="narrative-box"><div class="narrative-box-title">名望描述</div><span id="char-fame-desc"></span></div>

        <div class="divider"></div>
        <div class="narrative-box-title" style="text-align:center;">个人属性</div>
        <div class="info-grid" style="gap:10px; margin-top:8px;">
          <div class="info-item" style="border:none;">
            <div style="display:flex; justify-content:space-between;"><span class="info-label">政治</span><span id="attr-pol-val" style="font-size:13px;font-weight:bold;color:var(--ink-dark);"></span></div>
            <div class="ability-bar-container"><div id="attr-pol-bar" class="ability-bar"></div></div>
          </div>
          <div class="info-item" style="border:none;">
            <div style="display:flex; justify-content:space-between;"><span class="info-label">统领</span><span id="attr-ldr-val" style="font-size:13px;font-weight:bold;color:var(--ink-dark);"></span></div>
            <div class="ability-bar-container"><div id="attr-ldr-bar" class="ability-bar"></div></div>
          </div>
          <div class="info-item" style="border:none;">
            <div style="display:flex; justify-content:space-between;"><span class="info-label">学识</span><span id="attr-knw-val" style="font-size:13px;font-weight:bold;color:var(--ink-dark);"></span></div>
            <div class="ability-bar-container"><div id="attr-knw-bar" class="ability-bar"></div></div>
          </div>
          <div class="info-item" style="border:none;">
            <div style="display:flex; justify-content:space-between;"><span class="info-label">健康</span><span id="attr-hp-val" style="font-size:13px;font-weight:bold;color:var(--qin-red);"></span></div>
            <div class="ability-bar-container" style="background:#e8dcc4; border-color:var(--qin-red);"><div id="attr-hp-bar" class="ability-bar" style="background:var(--qin-red);"></div></div>
          </div>
          <div class="info-item" style="border:none;">
            <div style="display:flex; justify-content:space-between;"><span class="info-label">风采</span><span id="attr-chm-val" style="font-size:13px;font-weight:bold;color:var(--ink-dark);"></span></div>
            <div class="ability-bar-container"><div id="attr-chm-bar" class="ability-bar"></div></div>
          </div>
          <div class="info-item" style="border:none;">
            <div style="display:flex; justify-content:space-between;"><span class="info-label">武艺</span><span id="attr-mrt-val" style="font-size:13px;font-weight:bold;color:var(--ink-dark);"></span></div>
            <div class="ability-bar-container"><div id="attr-mrt-bar" class="ability-bar"></div></div>
          </div>
        </div>
      </div>
    </div>

    <!-- 2. 世界时局 -->
    <div class="section">
      <div class="section-header collapsed"><span>◆ 世界时局</span></div>
      <div class="section-content hidden">
        <div class="info-grid">
          <div class="info-item" style="grid-column: span 2; border:none;"><span class="info-label">时势: <span id="world-title" style="font-weight:bold;color:var(--qin-red);"></span></span><span id="world-desc" style="font-size:13px; margin-top:4px; line-height:1.4;"></span></div>
          <div class="info-item" style="margin-top:8px;"><span class="info-label">观测史观</span><span id="world-view" class="info-value" style="color:var(--ink-dark);"></span></div>
        </div>
        <div class="narrative-box"><div class="narrative-box-title">谶纬流传</div><span id="world-prophecy"></span></div>
      </div>
    </div>

    <!-- 3. 经济声誉 -->
    <div class="section">
      <div class="section-header collapsed"><span>◆ 经济声誉</span></div>
      <div class="section-content hidden">
        <div class="narrative-box-title">储备列表</div>
        <div class="info-grid" id="reserve-grid" style="margin-bottom:10px;"></div>
        <div class="divider"></div>
        <div class="narrative-box-title">资产列表</div>
        <ul class="scroll-list" id="asset-list"></ul>
        <div class="divider"></div>
        <div class="narrative-box-title">阶级评价</div>
        <ul class="scroll-list" id="eval-list"></ul>
        <div class="divider"></div>
        <div class="narrative-box-title">过往履历</div>
        <ul class="scroll-list" id="hist-list"></ul>
      </div>
    </div>

    <!-- 4. 天下势力 (独立) -->
    <div class="section">
      <div class="section-header collapsed"><span>◆ 天下势力</span></div>
      <div class="section-content hidden">
        <ul class="scroll-list" id="fac-list"></ul>
      </div>
    </div>

    <!-- 5. 麾下兵将 (部曲+下属) -->
    <div class="section">
      <div class="section-header collapsed"><span>◆ 麾下兵将</span></div>
      <div class="section-content hidden">
        <div class="narrative-box-title">麾下部曲</div>
        <ul class="scroll-list" id="army-list"></ul>
        <div class="divider"></div>
        <div class="narrative-box-title">直属下属</div>
        <ul class="scroll-list" id="sub-list"></ul>
      </div>
    </div>

    <!-- 6. 宗族与交游 -->
    <div class="section">
      <div class="section-header collapsed"><span>◆ 宗族与交游</span></div>
      <div class="section-content hidden">
        <div class="info-grid">
          <div class="info-item"><span class="info-label">家族名</span><span id="fam-name" class="info-value"></span></div>
          <div class="info-item"><span class="info-label">家族等级</span><span id="fam-lvl" class="info-value" style="color:var(--ink-dark);"></span></div>
          <div class="info-item" style="grid-column: span 2;"><span class="info-label">家族领袖</span><span id="fam-leader" class="info-value"></span></div>
        </div>
        <div class="divider"></div>
        <div class="narrative-box-title">家族子弟</div>
        <ul class="scroll-list" id="fam-mem-list"></ul>
        <div class="narrative-box" style="margin-top:4px;"><div class="narrative-box-title">家族动向</div><span id="fam-dyn"></span></div>
        <div class="divider"></div>
        <div class="narrative-box-title">人际交往</div>
        <ul class="scroll-list" id="rel-list"></ul>
      </div>
    </div>

    <!-- 7. 内闱与子嗣 -->
    <div class="section">
      <div class="section-header collapsed"><span>◆ 内闱与子嗣</span></div>
      <div class="section-content hidden">
        <div class="narrative-box-title" style="color:var(--qin-red);">内闱妻妾 <span style="font-size:10px;font-weight:normal;color:#8b795e;">(点击查看详情)</span></div>
        <ul class="scroll-list" id="harem-list" style="margin-top:8px;"></ul>
        <div class="narrative-box" style="margin-top:4px;"><div class="narrative-box-title">后宫动态</div><span id="harem-dyn"></span></div>

        <div class="divider"></div>

        <div class="narrative-box-title">膝下子嗣</div>
