let userData = {
    category: null,
    figureId: null,
    scenarioId: null,
    talents: {},
    bgInfo: ''
};

let currentPage = 0;

function goToPage(n) {
    document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
    document.getElementById('page-' + n)?.classList.add('active');
    currentPage = n;
}

function selectCategory(cat) {
    userData.category = cat;
    let data = Object.keys(worldData.historicalFigures)
        .filter(k => worldData.historicalFigures[k].category === cat)
        .map(k => {
            let f = worldData.historicalFigures[k];
            // 在卡片展示时只读取shortDesc(最高职位)，绝对不带表字
            return { name: k, title: k, desc: `${f.shortDesc}` };
        });
    renderCards('figure-cards', data, item => userData.figureId = item.name);
    document.getElementById('guide-category').innerText = `正在选择【${cat}】人物`;
    goToPage(2);
}

function renderCards(containerId, data, onSelect) {
    const container = document.getElementById(containerId);
    if (!container) return;
    container.innerHTML = '';
    data.forEach(item => {
        const card = document.createElement('div');
        card.className = 'card';
        if(item.disabled) card.classList.add('disabled');
        card.innerHTML = `<div class="card-title">${item.title || item.name}</div><div class="card-desc">${item.desc || item.reign || ''}</div>`;
        card.onclick = function() {
            if(item.disabled) return;
            document.querySelectorAll('#' + containerId + ' .card').forEach(c => c.classList.remove('selected'));
            card.classList.add('selected');
            if (onSelect) onSelect(item);
        };
        container.appendChild(card);
    });
}

function saveFigure() {
    if (!userData.figureId) { alert('请选择人物'); return; }
    let figure = worldData.historicalFigures[userData.figureId];
    let scData = Object.keys(figure.scenarios).map(yr => {
        let sc = figure.scenarios[yr];
        let eraTitle = worldData.situationsInfo[yr] || '';
        return { name: yr, title: `${yr} - ${eraTitle}`, reign: sc.reign, desc: sc.crisis };
    });

    renderCards('scenario-cards', scData, item => {
        userData.scenarioId = item.name;
    });
    goToPage(3);
}

function saveScenario() {
    if (!userData.scenarioId) { alert('请选择切入纪元'); return; }
    setupTalentUI();
    goToPage(4);
}

function setupTalentUI() {
    const container = document.getElementById('talent-selection-area');
    if (!container) return;
    container.innerHTML = '';

    let figure = worldData.historicalFigures[userData.figureId];
    let sc = figure.scenarios[userData.scenarioId];

    if(Object.keys(userData.talents).length === 0 || !userData.talents._initScenario || userData.talents._initScenario !== userData.scenarioId) {
        userData.talents = Object.assign({}, sc.baseTalents);
        userData.talents._initScenario = userData.scenarioId;
    }

    worldData.talents.forEach((tName, index) => {
        const group = document.createElement('div');
        group.className = 'talent-group';
        const currentVal = userData.talents[tName] || `常人 ${tName}+0`;
        userData.talents[tName] = currentVal;

        group.innerHTML = `
            <input type="text" class="talent-input" id="talent-input-${index}" value="${currentVal}">
            <button class="btn-refresh" onclick="refreshTalent('${tName}', ${index})">抽取</button>
        `;
        container.appendChild(group);

        group.querySelector('.talent-input').addEventListener('input', (e) => {
            userData.talents[tName] = e.target.value;
        });
    });
}

window.refreshTalent = function(tName, index) {
    const pool = worldData.talentPresets.filter(p => p.includes(tName));
    let randomText = `常人 ${tName}+0`;
    if(pool.length > 0) randomText = pool[Math.floor(Math.random() * pool.length)];
    const input = document.getElementById(`talent-input-${index}`);
    input.value = randomText;
    userData.talents[tName] = randomText;
}

function saveTalent() {
    let figure = worldData.historicalFigures[userData.figureId];
    document.getElementById('input-children').value = figure.defaultChildren || '';

    displaySummary();
    goToPage(5);
}

function formatTalents() {
    let arr = [];
    for (let k in userData.talents) {
        if(k !== '_initScenario' && userData.talents[k] && !userData.talents[k].includes('+0')) {
            arr.push(`[${userData.talents[k]}]`);
        }
    }
    return arr.length > 0 ? arr.join('，') : '无出奇之处';
}

function getFinalDataObj() {
    let figure = worldData.historicalFigures[userData.figureId];
    let sc = figure.scenarios[userData.scenarioId];
    return {
        name: figure.name || userData.figureId,
        zi: figure.zi, // 表字字段
        faction: sc.faction,
        classType: figure.classType,
        reputation: sc.reputation,
        reign: sc.reign,
        year: userData.scenarioId,
        age: sc.age,
        position: sc.position,
        region: sc.region,
        forceName: sc.forceName,
        power: sc.power,
        sub: sc.sub,
        industry: sc.industry,
        crisis: sc.crisis
    };
}

function displaySummary() {
    let d = getFinalDataObj();
    let eraTitle = worldData.situationsInfo[d.year] || '';

    // 只有在最终总结页才会加上表字
    let html = `
        <strong>时代大势:</strong> ${d.year} - ${eraTitle} [${d.reign}]<br>
        <strong>人物名讳:</strong> ${d.name} ${d.zi !== '无' ? '('+d.zi+')' : ''} [${d.age}岁]<br>
        <strong>身份官职:</strong> ${d.faction} | ${d.position}<br>
        <strong>所在地域:</strong> ${d.region}<br>
        <strong>当世名望:</strong> ${d.reputation}<br>
        <strong>天资秉赋:</strong> ${formatTalents()}<br>
        <strong>势力兵马:</strong> ${d.forceName} (${d.power})<br>
        <strong>核心从属:</strong> ${d.sub}<br>
        <strong>产业收支:</strong> ${d.industry}<br>
        <strong>当前剧本危机:</strong> ${d.crisis}<br>
    `;

    document.getElementById('summary-info').innerHTML = html;
}

function openEditMenu() {
    const container = document.getElementById('edit-list-container');
    container.innerHTML = '';

    let d = getFinalDataObj();
    let fields = [
        { key: 'faction', label: '阵营势力', val: d.faction },
        { key: 'age', label: '年龄', val: d.age },
        { key: 'region', label: '所在地域', val: d.region },
        { key: 'power', label: '兵马数量', val: d.power },
        { key: 'sub', label: '核心从属', val: d.sub },
        { key: 'reputation', label: '当世名望', val: d.reputation },
        { key: 'industry', label: '产业及收支', val: d.industry },
        { key: 'crisis', label: '危机剧本', val: d.crisis, type: 'textarea' }
    ];

    fields.forEach(f => {
        let inputHtml = f.type === 'textarea'
            ? `<textarea id="edit-input-${f.key}" class="edit-form-input" style="min-height: 80px; resize: vertical;">${f.val}</textarea>`
            : `<input type="text" id="edit-input-${f.key}" class="edit-form-input" value="${f.val}">`;

        container.innerHTML += `
            <div class="edit-form-group">
                <label class="edit-form-label">${f.label}</label>
                ${inputHtml}
            </div>
        `;
    });

    document.getElementById('edit-menu-modal').classList.add('show');
}

function saveEditedInfo() {
    let figure = worldData.historicalFigures[userData.figureId];
    let sc = figure.scenarios[userData.scenarioId];

    sc.faction = document.getElementById('edit-input-faction').value.trim();
    sc.age = document.getElementById('edit-input-age').value.trim();
    sc.region = document.getElementById('edit-input-region').value.trim();
    sc.power = document.getElementById('edit-input-power').value.trim();
    sc.sub = document.getElementById('edit-input-sub').value.trim();
    sc.reputation = document.getElementById('edit-input-reputation').value.trim();
    sc.industry = document.getElementById('edit-input-industry').value.trim();
    sc.crisis = document.getElementById('edit-input-crisis').value.trim();

    closeEditMenu();
    displaySummary();
}

function closeEditMenu() {
    document.getElementById('edit-menu-modal').classList.remove('show');
}

function getFinalText() {
    userData.bgInfo = document.getElementById('input-custom-bg').value.trim();
    let childInfo = document.getElementById('input-children').value.trim();
    let d = getFinalDataObj();
    let eraTitle = worldData.situationsInfo[d.year] || '';

    let lines = [];
    lines.push('我的秦汉历史人物剧本设定已确认，请严格基于以下史实数据与设定进行推演：\n');
    lines.push(`【时代节点】：${d.year} - ${eraTitle} [${d.reign}]`);
    // 输出文本也会加上表字
    lines.push(`【角色身份】：${d.name}${d.zi !== '无' ? '，字'+d.zi : ''}，年方${d.age}岁。身份为[${d.faction}]阵营，现居[${d.position}]之位，坐镇[${d.region}]。`);
    lines.push(`【名望天资】：初始名望为[${d.reputation}]。天赋特性：${formatTalents()}。`);
    lines.push(`【军政实力】：统率[${d.forceName}]，坐拥[${d.power}]，麾下有核心从属[${d.sub}]辅助。`);
    lines.push(`【名下产业】：当前资产状态为 [${d.industry}]。`);
    if(childInfo) lines.push(`【子嗣家室】：${childInfo}`);
    if(userData.bgInfo) lines.push(`【执念与背景】：${userData.bgInfo}`);
    lines.push(`【当前生死危机】：${d.crisis}`);

    lines.push('\n命运的竹简已然铺开，天下棋局皆在眼前。请以白描手法和符合时代设定的语言，直接开始描绘我当下面临的具体情境与抉择。');

    return lines.join('\n');
}

function showPreviewModal() {
    document.getElementById('preview-textarea').value = getFinalText();
    document.getElementById('preview-modal').classList.add('show');
}

function closePreviewModal() {
    document.getElementById('preview-modal').classList.remove('show');
}

function copyPreviewText() {
    const t = document.getElementById('preview-textarea');
    t.select();
    try { navigator.clipboard.writeText(t.value); alert('已复制'); }
    catch(e) { document.execCommand('copy'); alert('已复制'); }
}

function onConfirm() {
    try {
        const text = getFinalText();
        if (typeof getCharWorldbookNames === 'function' && typeof createChatMessages === 'function') {
            const wbName = getCharWorldbookNames('current').primary;
            deleteWorldbookEntries(wbName, entry => entry.name === '秦汉用户信息').then(() => {
                return createWorldbookEntries(wbName, [{ name: '秦汉用户信息', enabled: true, strategy: { type: 'constant' }, position: { type: 'before_character_definition' }, content: text }]);
            }).then(() => createChatMessages([{ role: 'user', message: text }]))
              .then(() => triggerSlash('/send'));
        } else {
            console.log(text);
            alert("非酒馆环境，已输出至浏览器控制台。\n\n" + text);
        }
    } catch(e) {
        alert("环境不支持API调用，设定已输出至控制台。");
        console.log(getFinalText());
    }
}

window.onload = () => {
    // 默认停留在PAGE 0，点击"择选阵营"去PAGE 1
};

</script>
</body>
</html>
